# frozen_string_literal: true

require "digest/sha2"
require "open3"
require "open-uri"
require "tempfile"
require "tmpdir"

module Dev
  module Deps
    # Generates, parses, and validates CMake lockfiles (deps.lock.cmake / deps.targets.cmake)
    # from the dependency config declared via Dev::Deps.define.
    module Lockfile
      LOCK_HEADER = <<~TEXT
        # Lockfile: repo+sha or url (optional hash) per runtime dep. Generated by dev deps - do not edit.
        # Lists below are per build target (app vs test), not per dev environment (ci/dev).
        # Edit dependencies.rb and re-run setup to change.
        # URL-based deps: hash is lockfile-only (reuse from lockfile or set UPDATE_DEPS_FETCH_URL_HASH=1 to fetch and pin).

      TEXT
      TARGETS_HEADER = <<~TEXT
        # Runtime targets/includes per dep. Generated by dev deps.
        # Used by cmake/Deps.cmake when resolving each build target (app / test).
        # Edit dependencies.rb and re-run setup to change.

      TEXT

      # Regenerate deps.lock.cmake and deps.targets.cmake from Dev::Deps::Config.
      def self.update(root:, lock_path: nil, targets_path: nil, quiet: false)
        lock_path    ||= File.join(root, "deps.lock.cmake")
        targets_path ||= File.join(root, "deps.targets.cmake")
        real_lock_path = File.join(root, "deps.lock.cmake")

        old_hash = file_hash(lock_path)
        old_hashes = {}
        old_shas = {}
        if File.file?(real_lock_path)
          content = File.read(real_lock_path)
          content.scan(/set\(dep_(\w+)_hash\s+"([^"]+)"\)/) { old_hashes[Regexp.last_match(1)] = Regexp.last_match(2) }
          content.scan(/set\(dep_(\w+)_sha\s+"([^"]+)"\)/) { old_shas[Regexp.last_match(1)] = Regexp.last_match(2) }
        end
        had_old_lockfile = !old_hash.nil?

        File.unlink(lock_path) if File.file?(lock_path)
        File.unlink(targets_path) if File.file?(targets_path)

        File.write(lock_path, LOCK_HEADER)
        File.write(targets_path, TARGETS_HEADER)

        app_deps = []
        test_deps = []
        any_changed = false

        runtime_entries.each do |name, kind, repo_or_url, ref, env, opts|
          next if name.nil? || name.empty?

          if kind == "url"
            append(lock_path, "set(dep_#{name}_url \"#{repo_or_url}\")\n")
            hash = old_hashes[name]
            hash = fetch_url_sha256(repo_or_url, name, quiet: quiet) if hash.nil? && fetch_url_hash?
            if hash.nil?
              step_warning("#{name}: URL dep has no hash (set UPDATE_DEPS_FETCH_URL_HASH=1 to fetch and pin).", quiet: quiet)
            else
              append(lock_path, "set(dep_#{name}_hash \"#{hash}\")\n")
            end
            append(lock_path, "set(dep_#{name}_tag \"#{opts[:tag]}\")\n") if opts[:tag]
            dep_label = env == "test" ? "#{name} (test)" : name
            step_ok(dep_label, quiet: quiet)
            step_detail("url: #{repo_or_url} , sha256: #{hash ? hash.sub(/\ASHA256=/, "") : "(none)"}", quiet: quiet)
            if had_old_lockfile && (old_hashes[name] != hash || old_hashes[name].nil?)
              any_changed = true
              step_changed(old_hashes[name], hash, format: :hash, quiet: quiet)
            end
            (env == "test" ? test_deps : app_deps) << name
          else
            sha = old_shas[name] || resolve_ref(repo_or_url, ref)
            append(lock_path, "set(dep_#{name}_repo \"#{repo_or_url}\")\n")
            append(lock_path, "set(dep_#{name}_sha \"#{sha}\")\n")
            dep_label = env == "test" ? "#{name} (test)" : name
            step_ok(dep_label, quiet: quiet)
            step_detail("repo: #{repo_or_url} ref=#{ref} -> sha=#{sha[0, 7]}", quiet: quiet)
            if had_old_lockfile && (old_shas[name] != sha || old_shas[name].nil?)
              any_changed = true
              step_changed(old_shas[name], sha, format: :sha, quiet: quiet)
            end
            (env == "test" ? test_deps : app_deps) << name
          end
        end

        append(lock_path, "set(RUNTIME_DEPS_APP \"#{app_deps.join(";")}\")\n") if app_deps.any?
        append(lock_path, "set(RUNTIME_DEPS_TEST \"#{test_deps.join(";")}\")\n") if test_deps.any?

        write_targets_cmake(targets_path)

        step_ok("Wrote #{File.basename(lock_path)}", quiet: quiet)
        step_warning("Review and commit deps.lock.cmake.") if any_changed && !quiet
      end

      # Parse deps.lock.cmake into an array of dep hashes:
      # { name:, repo:, sha: } for git, or { name:, url:, hash: } for tarball.
      def self.parse(lock_path)
        content = File.read(lock_path)
        repos = {}
        shas = {}
        content.scan(/set\(dep_(\w+)_repo\s+"([^"]+)"\)/) { repos[Regexp.last_match(1)] = Regexp.last_match(2) }
        content.scan(/set\(dep_(\w+)_sha\s+"([^"]+)"\)/) { shas[Regexp.last_match(1)] = Regexp.last_match(2) }
        urls = {}
        content.scan(/set\(dep_(\w+)_url\s+"([^"]+)"\)/) { urls[Regexp.last_match(1)] = Regexp.last_match(2) }
        hashes = {}
        content.scan(/set\(dep_(\w+)_hash\s+"([^"]+)"\)/) { hashes[Regexp.last_match(1)] = Regexp.last_match(2) }
        app = content[/set\(RUNTIME_DEPS_APP\s+"([^"]+)"\)/, 1].to_s.split(";")
        test = content[/set\(RUNTIME_DEPS_TEST\s+"([^"]+)"\)/, 1].to_s.split(";")
        (app + test).uniq.filter_map do |n|
          if urls[n]
            { name: n, url: urls[n], hash: hashes[n] }
          elsif repos[n] && shas[n]
            { name: n, repo: repos[n], sha: shas[n] }
          end
        end
      end

      # Check whether the committed lockfile is in sync with dependencies.rb.
      # Returns an array of dep names that differ. Raises if lockfile is missing.
      def self.check_sync!(root:)
        lock_path = File.join(root, "deps.lock.cmake")
        unless File.file?(lock_path)
          abort("deps.lock.cmake not found. Run update-deps to generate it from dependencies.rb, commit it, then run setup again.")
        end

        current_content = File.read(lock_path).strip
        generated_content = nil
        Dir.mktmpdir("dev-deps-lockfile-check-") do |tempdir|
          temp_lock = File.join(tempdir, "deps.lock.cmake")
          temp_targets = File.join(tempdir, "deps.targets.cmake")
          update(root: root, lock_path: temp_lock, targets_path: temp_targets, quiet: true)
          generated_content = File.read(temp_lock).strip
        end
        out_of_sync_deps(current_content, generated_content)
      end

      # Returns array of dep names whose lockfile entries differ.
      def self.out_of_sync_deps(current_content, generated_content)
        names_current = current_content.scan(/set\(dep_(\w+)_(?:repo|sha|url|hash)\s+"/).map(&:first).uniq
        names_generated = generated_content.scan(/set\(dep_(\w+)_(?:repo|sha|url|hash)\s+"/).map(&:first).uniq
        all_names = (names_current + names_generated).uniq.sort
        all_names.select { |n| signature_for(current_content, n) != signature_for(generated_content, n) }
      end

      def self.dep_pin(content, name)
        if (m = content.match(/set\(dep_#{Regexp.escape(name)}_sha\s+"([^"]+)"\)/))
          "sha=#{m[1].length >= 10 ? "#{m[1][0, 7]}..." : m[1]}"
        elsif (m = content.match(/set\(dep_#{Regexp.escape(name)}_hash\s+"([^"]+)"\)/))
          h = m[1].sub(/\ASHA256=/, "")
          "hash=#{h.length >= 12 ? "#{h[0, 12]}..." : h}"
        elsif content.include?("dep_#{name}_url")
          (m = content.match(/set\(dep_#{Regexp.escape(name)}_url\s+"([^"]+)"\)/)) ? "url=#{m[1]}" : "url=..."
        else
          "(no pin)"
        end
      end

      # Name -> ref (tag, commit) for display, from config.
      def self.runtime_ref_map
        map = {}
        [Config.group("app"), Config.group("test")].each do |group|
          (group["runtime"] || []).each do |dep_spec|
            dep_spec.each do |name, spec|
              next unless spec.is_a?(Hash)
              ref = spec["tag"] || spec["commit"] || spec["ref"]
              map[name.to_s] = ref.to_s if ref
            end
          end
        end
        map
      end

      # --- private helpers ---

      class << self
        private

        def signature_for(content, name)
          content.lines.select { |line| line.include?("dep_#{name}_") }.sort.join
        end

        def runtime_entries
          entries = []
          app_group = Config.group("app")
          (app_group["runtime"] || []).each do |dep_spec|
            dep_spec.each do |name, spec|
              next unless spec.is_a?(Hash)
              if spec["url"]
                entries << [name, "url", spec["url"], nil, nil, { tag: spec["tag"] }.compact]
              elsif spec["repo"]
                ref = spec["commit"] || spec["tag"]
                entries << [name, "repo", spec["repo"], ref, nil, {}] if ref
              end
            end
          end
          test_group = Config.group("test")
          (test_group["runtime"] || []).each do |dep_spec|
            dep_spec.each do |name, spec|
              next unless spec.is_a?(Hash)
              if spec["url"]
                entries << [name, "url", spec["url"], nil, "test", { tag: spec["tag"] }.compact]
              elsif spec["repo"]
                ref = spec["commit"] || spec["tag"]
                entries << [name, "repo", spec["repo"], ref, "test", {}] if ref
              end
            end
          end
          entries
        end

        def write_targets_cmake(targets_path)
          written = {}
          buf = []
          (Config.group("app")["runtime"] || []).each do |dep_spec|
            dep_spec.each do |name, spec|
              next unless spec.is_a?(Hash)
              written[name] = true
              if spec["cmake_targets"]
                buf << "set(dep_#{name}_cmake_targets \"#{Array(spec["cmake_targets"]).map(&:to_s).join(";")}\")"
              end
              if spec["cmake_namespace"]
                buf << "set(dep_#{name}_cmake_namespace \"#{spec["cmake_namespace"]}\")"
              end
              buf << "set(dep_#{name}_includes \"#{Array(spec["includes"]).map(&:to_s).join(";")}\")" if spec["includes"]
            end
          end
          (Config.group("test")["runtime"] || []).each do |dep_spec|
            dep_spec.each do |name, spec|
              next unless spec.is_a?(Hash)
              next if written[name]
              if spec["cmake_targets"]
                buf << "set(dep_#{name}_cmake_targets \"#{Array(spec["cmake_targets"]).map(&:to_s).join(";")}\")"
              end
              if spec["cmake_namespace"]
                buf << "set(dep_#{name}_cmake_namespace \"#{spec["cmake_namespace"]}\")"
              end
              buf << "set(dep_#{name}_includes \"#{Array(spec["includes"]).map(&:to_s).join(";")}\")" if spec["includes"]
            end
          end
          File.open(targets_path, "a") { |f| f.puts(buf) }
        end

        def append(path, content)
          File.open(path, "a") { |f| f.write(content) }
        end

        def file_hash(path)
          return nil unless File.file?(path)
          Digest::SHA256.file(path).hexdigest
        end

        def fetch_url_hash?
          ENV["UPDATE_DEPS_FETCH_URL_HASH"].to_s =~ /\A(1|true|yes)\z/i
        end

        def fetch_url_sha256(url, name, quiet: false)
          step_detail("fetching #{name} to compute hash...", quiet: quiet)
          Tempfile.create(["dev_deps_#{name}", ".bin"]) do |tmp|
            tmp.binmode
            OpenURI.open_uri(url) { |io| IO.copy_stream(io, tmp) }
            tmp.flush
            hex = Digest::SHA256.file(tmp.path).hexdigest
            "SHA256=#{hex}"
          end
        rescue OpenURI::HTTPError, SocketError, Errno::ECONNREFUSED, Errno::ETIMEDOUT => e
          step_warning("could not fetch #{name}: #{e.message}", quiet: quiet)
          nil
        end

        def resolve_ref(repo, ref)
          out, _err, status = Open3.capture3("git", "ls-remote", "--tags", repo, ref.to_s)
          return out.lines.first.split.first if status.success? && !out.strip.empty?
          out, _err, status = Open3.capture3("git", "ls-remote", repo, "refs/heads/#{ref}")
          return out.lines.first.split.first if status.success? && !out.strip.empty?
          return ref if ref.to_s.length == 40 && ref.to_s.match?(/\A[0-9a-f]+\z/)
          raise "Could not resolve ref '#{ref}' for #{repo}"
        end

        # --- UI helpers (CLI::UI optional) ---

        def cli_ui_available?
          Brew.cli_ui_available?
        end

        def step_ok(label, quiet: false)
          return if quiet
          if cli_ui_available?
            CLI::UI.puts("#{CLI::UI::Glyph::CHECK} #{label}")
          else
            puts "  ok: #{label}"
          end
        end

        def step_detail(msg, quiet: false)
          return if quiet
          puts "  #{msg}"
        end

        def step_warning(msg, quiet: false)
          return if quiet
          if cli_ui_available?
            CLI::UI.puts(CLI::UI.fmt("{{yellow:#{msg}}}"))
          else
            puts "  WARNING: #{msg}"
          end
        end

        def step_changed(old_val, new_val, format: :sha, quiet: false)
          return if quiet
          old_display = if old_val.nil?
            "(new)"
          elsif format == :sha
            old_val.to_s[0, 7]
          else
            old_val.to_s.sub(/\ASHA256=/, "")[0, 12]
          end
          new_display = format == :sha ? new_val.to_s[0, 7] : new_val.to_s.sub(/\ASHA256=/, "")[0, 12]
          if cli_ui_available?
            CLI::UI.puts(CLI::UI.fmt("{{yellow:was #{old_display} -> now #{new_display}}}"))
          else
            puts "  changed: was #{old_display} -> now #{new_display}"
          end
        end
      end
    end
  end
end
